        + ASSERTION_FILE_MUTUAL_EXCLUSION_NOTICE;

    public static final String SASL_OAUTHBEARER_ASSERTION_PRIVATE_KEY_PASSPHRASE = "sasl.oauthbearer.assertion.private.key.passphrase";
